const fs = require('fs');
const path = 'src/pages/client/ContactPage.jsx';
let content = fs.readFileSync(path, 'utf8');

const newCode = `  const handleSubmit = async (e) => {
    e.preventDefault();
    setUiState((prev) => ({ ...prev, isSubmitting: true }));
    try {
      const baseUrl = import.meta.env.VITE_BACKEND_URL;
      await axios.post(\`\${baseUrl}/api/messages\`, formData);
      setUiState((prev) => ({ ...prev, isSubmitting: false, isSubmitted: true }));
      setFormData({ name: "", email: "", phone: "", subject: "", message: "" });
      setTimeout(() => setUiState((prev) => ({ ...prev, isSubmitted: false })), 5000);
    } catch (error) {
      console.error("Failed to submit message:", error);
      setUiState((prev) => ({ ...prev, isSubmitting: false }));
    }
  };

  const handleChatSend`;

// Split content by const handleSubmit
const parts1 = content.split("const handleSubmit =");
const prefix = parts1[0];
const remaining = parts1[1];
const parts2 = remaining.split("const handleChatSend");
const suffix = parts2[1];

if (parts1.length === 2 && parts2.length === 2) {
    fs.writeFileSync(path, prefix + newCode + suffix, 'utf8');
    console.log("Success! File replaced and handles newline differences.");
} else {
    console.log("Failed to find boundaries in ContactPage.jsx");
}

import { useEffect, useRef, useState } from "react";
import axios from "axios";
import { BsCart4, BsSunFill, BsMoonFill } from "react-icons/bs";
import { RxHamburgerMenu, RxCross2 } from "react-icons/rx";
import { FaUserCircle } from "react-icons/fa";
import { FiHome, FiBox, FiPhoneCall, FiHeart } from "react-icons/fi";
import { Link, useLocation, useNavigate } from "react-router-dom";
import ShinyText from "./ShinyText";
import getCart from "../utils/cart";
import { useAuth } from "../context/AuthContext";

export default function Header() {
  const [isOpen, setIsOpen] = useState(false);
  const [darkMode, setDarkMode] = useState(() => {
    const savedTheme = localStorage.getItem("theme");
    return savedTheme === "dark";
  });
  const [scrolled, setScrolled] = useState(false);
  const { user, logout } = useAuth();
  const [userMenuOpen, setUserMenuOpen] = useState(false);
  const [cartCount, setCartCount] = useState(0);
  const userMenuRef = useRef(null);
  const location = useLocation();
  const navigate = useNavigate();

  // Apply theme to entire document
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add("dark");
      localStorage.setItem("theme", "dark");
    } else {
      document.documentElement.classList.remove("dark");
      localStorage.setItem("theme", "light");
    }
  }, [darkMode]);

  // Handle scroll effect
  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const getCartCount = () =>
    getCart().reduce(
      (total, item) => total + Number(item?.quantity ?? 0),
      0,
    );

  useEffect(() => {
    setUserMenuOpen(false);
    setCartCount(getCartCount());
  }, [location.pathname]);

  useEffect(() => {
    const handleCartUpdate = () => {
      setCartCount(getCartCount());
    };
    window.addEventListener("cart:updated", handleCartUpdate);
    return () => window.removeEventListener("cart:updated", handleCartUpdate);
  }, []);

  useEffect(() => {
    const handleOutsideClick = (event) => {
      if (userMenuRef.current && !userMenuRef.current.contains(event.target)) {
        setUserMenuOpen(false);
      }
    };

    document.addEventListener("mousedown", handleOutsideClick);
    return () => document.removeEventListener("mousedown", handleOutsideClick);
  }, []);

  const toggleTheme = () => {
    setDarkMode(!darkMode);
  };

  const isActive = (path) => {
    if (path === "/") return location.pathname === "/";
    return location.pathname.startsWith(path);
  };

  const navItems = [
    { path: "/home", label: "Home", icon: <FiHome className="text-lg mb-[2px]" /> },
    {
      path: "/products",
      label: "Products",
      icon: <FiBox className="text-lg mb-[2px]" />,
    },
    {
      path: "/contact",
      label: "Contact",
      icon: <FiPhoneCall className="text-lg mb-[2px]" />,
    },
    {
      path: "/reviews",
      label: "Reviews",
      icon: <FiHeart className="text-lg mb-[2px]" />,
    },
  ];

  const displayName = user
    ? `${user.firstName ?? ""} ${user.lastName ?? ""}`.trim() ||
      user.name ||
      user.email ||
      "Account"
    : "Account";
  const avatarUrl =
    user?.profilePicture || user?.avatar || user?.image || null;
  const handleLogout = () => {
    logout();
    setUserMenuOpen(false);
    navigate("/login");
  };

  return (
    <>
      <header
        className={`sticky top-0 z-50 transition-all duration-300 ${
          scrolled
            ? "bg-white/95 dark:bg-gray-900/95 backdrop-blur-xl shadow-lg dark:shadow-gray-900/50 py-3"
            : "bg-white dark:bg-gray-900 py-4"
        }`}
      >
        <div className="container mx-auto px-4 md:px-6 lg:px-8">
          <div className="flex items-center justify-between">
            {/* Logo Section */}
            <Link to="/home" className="flex items-center space-x-3 group">
              <div className="relative flex-shrink-0">
                {/* Dynamically switching logo based on dark mode */}
                <img
                  src={darkMode ? "/logo.png" : "/logo.png"}
                  alt="Githmi Sports Goods Logo"
                  className="h-12 w-auto object-contain transition-transform duration-500 group-hover:scale-105"
                />
              </div>
              <div className="hidden sm:block">
                <h1 className="text-2xl md:text-3xl lg:text-4xl font-bold uppercase tracking-tight">
                  {/* ✨ SHINY TEXT COMPONENT ✨ */}
                  <ShinyText
                    text="Githmi Sports Goods"
                    disabled={false}
                    speed={3}
                    className={darkMode ? "text-[#a855f7]" : "text-[#4f46e5]"}
                  />
                </h1>
              </div>
            </Link>

            {/* Desktop Navigation */}
            <nav className="hidden lg:flex items-center space-x-1">
              {navItems.map((item) => (
                <Link
                  key={item.path}
                  to={item.path}
                  className={`flex items-center space-x-2 px-4 py-2.5 rounded-xl transition-all duration-300 ${
                    isActive(item.path)
                      ? "bg-gradient-to-r from-blue-500/10 to-purple-500/10 text-blue-600 dark:text-blue-400"
                      : "text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800"
                  }`}
                >
                  <span className="text-lg">{item.icon}</span>
                  <span className="font-medium">{item.label}</span>
                  {isActive(item.path) && (
                    <div className="w-1.5 h-1.5 bg-gradient-to-r from-blue-500 to-purple-500 rounded-full ml-1"></div>
                  )}
                </Link>
              ))}
            </nav>

            {/* Right Side Actions */}
            <div className="flex items-center space-x-3 md:space-x-4">
              {/* Theme Toggle */}
              <button
                onClick={toggleTheme}
                className="hidden sm:flex w-16 h-8 bg-gray-900 dark:bg-gray-200 rounded-full p-1 items-center transition-colors duration-300 shadow-inner"
                aria-label="Toggle theme"
              >
                <div
                  className={`w-6 h-6 bg-white dark:bg-gray-900 rounded-full flex items-center justify-center transform transition-transform duration-300 ${
                    darkMode ? "translate-x-8" : "translate-x-0"
                  }`}
                >
                  {darkMode ? (
                    <BsMoonFill className="text-gray-900 dark:text-white text-xs" />
                  ) : (
                    <BsSunFill className="text-gray-900 dark:text-white text-xs" />
                  )}
                </div>
              </button>

              {/* Cart */}
              <Link
                to="/cart"
                className="relative p-2.5 rounded-xl bg-gradient-to-br from-gray-100 to-gray-200 dark:from-gray-800 dark:to-gray-900 shadow-sm hover:shadow-md transition-all duration-300 group"
              >
                <BsCart4 className="w-5 h-5 text-gray-700 dark:text-gray-300 group-hover:text-blue-600 dark:group-hover:text-blue-400 transition-colors duration-300" />
                {cartCount > 0 && (
                  <span className="absolute -top-1 -right-1 w-5 h-5 bg-gradient-to-r from-red-500 to-pink-500 text-white text-xs rounded-full flex items-center justify-center font-bold animate-pulse">
                    {cartCount}
                  </span>
                )}
              </Link>

              {/* Auth / User (Desktop) */}
              {user ? (
                <div
                  ref={userMenuRef}
                  className="relative hidden md:flex items-center pl-2 border-l border-gray-200 dark:border-gray-700"
                >
                  <button
                    onClick={() => setUserMenuOpen((prev) => !prev)}
                    className="flex items-center gap-2 rounded-xl border border-gray-200 dark:border-gray-700 bg-white/90 dark:bg-gray-800/90 px-3 py-2 text-sm font-semibold text-gray-700 dark:text-gray-200 shadow-sm transition-all hover:-translate-y-0.5 hover:shadow-md"
                  >
                    {avatarUrl ? (
                      <img
                        src={avatarUrl}
                        alt={displayName}
                        className="h-8 w-8 rounded-full object-cover"
                      />
                    ) : (
                      <FaUserCircle className="text-xl text-gray-600 dark:text-gray-300" />
                    )}
                    <span className="hidden lg:inline max-w-[220px] truncate">
                      {displayName}
                    </span>
                  </button>

                  {userMenuOpen && (
                    <div className="absolute right-0 top-12 w-64 rounded-2xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 shadow-xl p-4">
                      <div className="flex items-center gap-3">
                        {avatarUrl ? (
                          <img
                            src={avatarUrl}
                            alt={displayName}
                            className="h-10 w-10 rounded-full object-cover"
                          />
                        ) : (
                          <div className="h-10 w-10 rounded-full bg-gray-100 dark:bg-gray-800 flex items-center justify-center">
                            <FaUserCircle className="text-xl text-gray-500 dark:text-gray-300" />
                          </div>
                        )}
                        <div className="min-w-0">
                          <p className="font-bold text-gray-900 dark:text-white truncate">
                            {displayName}
                          </p>
                          {user?.email && (
                            <p className="text-xs text-gray-500 dark:text-gray-400 truncate">
                              {user.email}
                            </p>
                          )}
                        </div>
                      </div>

                      {user?.role === "admin" && (
                        <Link
                          to="/admin"
                          onClick={() => setUserMenuOpen(false)}
                          className="mt-4 block w-full rounded-xl bg-indigo-50 dark:bg-indigo-900/40 py-2.5 text-center text-sm font-bold text-indigo-700 dark:text-indigo-300 transition-all hover:bg-indigo-100 dark:hover:bg-indigo-900/60"
                        >
                          Dashboard
                        </Link>
                      )}

                      <button
                        onClick={handleLogout}
                        className="mt-4 w-full rounded-xl bg-gray-900 dark:bg-gray-100 py-2 text-sm font-bold text-white dark:text-gray-900 transition-all hover:-translate-y-0.5 hover:shadow-md"
                      >
                        Logout
                      </button>
                    </div>
                  )}
                </div>
              ) : (
                <div className="hidden md:flex items-center space-x-3 pl-2 border-l border-gray-200 dark:border-gray-700">
                  <Link
                    to="/login"
                    className="bg-transparent border-2 border-[#4f46e5] dark:border-[#a855f7] text-[#4f46e5] dark:text-[#a855f7] hover:bg-[#eff6ff] dark:hover:bg-gray-800 font-bold py-2 px-5 rounded-xl shadow-sm hover:shadow-md transform hover:-translate-y-0.5 active:scale-95 transition-all duration-300 text-sm whitespace-nowrap"
                  >
                    Login
                  </Link>
                  <Link
                    to="/register"
                    className="bg-gradient-to-r from-[#4f46e5] to-[#a855f7] hover:from-[#4338ca] hover:to-[#9333ea] text-white font-bold py-2.5 px-5 rounded-xl shadow-md hover:shadow-lg hover:shadow-indigo-500/30 transform hover:-translate-y-0.5 active:scale-95 transition-all duration-300 text-sm whitespace-nowrap"
                  >
                    Register
                  </Link>
                </div>
              )}

              {/* Mobile Menu Button */}
              <button
                onClick={() => setIsOpen(true)}
                className="lg:hidden p-2.5 rounded-xl bg-gradient-to-br from-gray-100 to-gray-200 dark:from-gray-800 dark:to-gray-900 shadow-sm hover:shadow-md transition-all duration-300"
                aria-label="Open menu"
              >
                <RxHamburgerMenu className="w-5 h-5 text-gray-700 dark:text-gray-300" />
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Mobile Menu Overlay */}
      {isOpen && (
        <div className="fixed inset-0 z-[9999] lg:hidden">
          {/* Backdrop */}
          <div
            className="absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity"
            onClick={() => setIsOpen(false)}
          />

          {/* Menu Panel */}
          <div className="absolute right-0 top-0 h-full w-80 bg-white dark:bg-gray-900 shadow-2xl transform transition-transform duration-300 flex flex-col">
            {/* Menu Header */}
            <div className="p-6 border-b border-gray-200 dark:border-gray-800 flex items-center justify-between">
              <div className="flex items-center space-x-3">
                {/* Updated Mobile Menu Logo */}
                <img
                  src={darkMode ? "/logo-white.png" : "/logo.png"}
                  alt="Logo"
                  className="h-10 w-auto object-contain"
                />
                <div>
                  <h2 className="font-bold text-gray-900 dark:text-white">
                    Githmi Sports
                  </h2>
                  <p className="text-xs text-gray-500 dark:text-gray-400">
                    Navigation
                  </p>
                </div>
              </div>
              <button
                onClick={() => setIsOpen(false)}
                className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
              >
                <RxCross2 className="w-6 h-6 text-gray-700 dark:text-gray-300" />
              </button>
            </div>

            {/* Mobile Navigation Links */}
            <div className="flex-1 overflow-y-auto p-6">
              <div className="space-y-2">
                {navItems.map((item) => (
                  <Link
                    key={item.path}
                    to={item.path}
                    onClick={() => setIsOpen(false)}
                    className={`flex items-center space-x-4 p-4 rounded-xl transition-all duration-200 ${
                      isActive(item.path)
                        ? "bg-gradient-to-r from-blue-500/10 to-purple-500/10 border-l-4 border-blue-500"
                        : "hover:bg-gray-100 dark:hover:bg-gray-800"
                    }`}
                  >
                    <div
                      className={`w-10 h-10 rounded-lg flex items-center justify-center ${
                        isActive(item.path)
                          ? "bg-gradient-to-r from-blue-500 to-purple-500"
                          : "bg-gray-100 dark:bg-gray-800"
                      }`}
                    >
                      <span
                        className={`text-lg ${
                          isActive(item.path)
                            ? "text-white"
                            : "text-gray-600 dark:text-gray-400"
                        }`}
                      >
                        {item.icon}
                      </span>
                    </div>
                    <div className="flex-1">
                      <span
                        className={`font-medium ${
                          isActive(item.path)
                            ? "text-blue-600 dark:text-blue-400"
                            : "text-gray-700 dark:text-gray-300"
                        }`}
                      >
                        {item.label}
                      </span>
                    </div>
                  </Link>
                ))}

                {/* Mobile Cart */}
                <Link
                  to="/cart"
                  onClick={() => setIsOpen(false)}
                  className="flex items-center justify-between p-4 rounded-xl hover:bg-gray-100 dark:hover:bg-gray-800 transition-all duration-200 mt-2"
                >
                  <div className="flex items-center space-x-4">
                    <div className="w-10 h-10 rounded-lg bg-gray-100 dark:bg-gray-800 flex items-center justify-center">
                      <BsCart4 className="text-lg text-gray-600 dark:text-gray-400" />
                    </div>
                    <div>
                      <span className="font-medium text-gray-700 dark:text-gray-300">
                        Shopping Cart
                      </span>
                      <p className="text-sm text-gray-500 dark:text-gray-400">
                        {cartCount} items
                      </p>
                    </div>
                  </div>
                  {cartCount > 0 && (
                    <span className="w-6 h-6 bg-gradient-to-r from-red-500 to-pink-500 text-white text-xs rounded-full flex items-center justify-center font-bold">
                      {cartCount}
                    </span>
                  )}
                </Link>
              </div>

              {/* Theme Toggle (Mobile) */}
              <div className="mt-8 p-4 rounded-xl bg-gray-50 dark:bg-gray-800/50 flex items-center justify-between border border-gray-100 dark:border-gray-800">
                <div className="flex items-center space-x-3">
                  <div className="w-10 h-10 rounded-lg bg-white dark:bg-gray-700 flex items-center justify-center shadow-sm">
                    {darkMode ? (
                      <BsMoonFill className="text-lg text-purple-400" />
                    ) : (
                      <BsSunFill className="text-lg text-yellow-500" />
                    )}
                  </div>
                  <div>
                    <span className="font-medium text-gray-700 dark:text-gray-300 text-sm">
                      {darkMode ? "Dark Mode" : "Light Mode"}
                    </span>
                    <p className="text-sm text-gray-500 dark:text-gray-400">
                      Switch theme
                    </p>
                  </div>
                </div>
                <button
                  onClick={toggleTheme}
                  className="w-14 h-7 bg-gray-900 dark:bg-gray-200 rounded-full p-1 flex items-center transition-colors duration-300 shadow-inner"
                >
                  <div
                    className={`w-5 h-5 bg-white dark:bg-gray-900 rounded-full flex items-center justify-center transform transition-transform duration-300 ${
                      darkMode ? "translate-x-7" : "translate-x-0"
                    }`}
                  />
                </button>
              </div>

              {/* Auth / User (Mobile) */}
              {user ? (
                <div className="mt-6 rounded-2xl border border-gray-200 dark:border-gray-800 bg-white dark:bg-gray-900 p-4">
                  <div className="flex items-center gap-3">
                    {avatarUrl ? (
                      <img
                        src={avatarUrl}
                        alt={displayName}
                        className="h-10 w-10 rounded-full object-cover"
                      />
                    ) : (
                      <div className="h-10 w-10 rounded-full bg-gray-100 dark:bg-gray-800 flex items-center justify-center">
                        <FaUserCircle className="text-xl text-gray-500 dark:text-gray-300" />
                      </div>
                    )}
                    <div className="min-w-0">
                      <p className="font-bold text-gray-900 dark:text-white truncate">
                        {displayName}
                      </p>
                      {user?.email && (
                        <p className="text-xs text-gray-500 dark:text-gray-400 truncate">
                          {user.email}
                        </p>
                      )}
                    </div>
                  </div>

                  {user?.role === "admin" && (
                    <Link
                      to="/admin"
                      onClick={() => setIsOpen(false)}
                      className="mt-4 block w-full rounded-xl bg-indigo-50 dark:bg-indigo-900/40 py-3 text-center text-sm font-bold text-indigo-700 dark:text-indigo-300 transition-all active:scale-95"
                    >
                      Admin Dashboard
                    </Link>
                  )}

                  <button
                    onClick={() => {
                      setIsOpen(false);
                      handleLogout();
                    }}
                    className="mt-4 w-full rounded-xl bg-gray-900 dark:bg-gray-100 py-3 text-sm font-bold text-white dark:text-gray-900 transition-all active:scale-95"
                  >
                    Logout
                  </button>
                </div>
              ) : (
                <div className="mt-6 flex flex-col gap-3">
                  <Link
                    to="/login"
                    onClick={() => setIsOpen(false)}
                    className="w-full bg-transparent border-2 border-[#4f46e5] dark:border-[#a855f7] text-[#4f46e5] dark:text-[#a855f7] hover:bg-[#eff6ff] dark:hover:bg-gray-800 font-bold py-3 rounded-xl shadow-sm transform active:scale-95 transition-all duration-300 text-center"
                  >
                    Login
                  </Link>
                  <Link
                    to="/register"
                    onClick={() => setIsOpen(false)}
                    className="w-full bg-gradient-to-r from-[#4f46e5] to-[#a855f7] text-white font-bold py-3.5 rounded-xl shadow-md transform active:scale-95 transition-all duration-300 text-center"
                  >
                    Register
                  </Link>
                </div>
              )}
            </div>

            {/* Menu Footer */}
            <div className="p-6 border-t border-gray-200 dark:border-gray-800">
              <div className="text-center">
                <p className="text-xs text-gray-500 dark:text-gray-400">
                  © 2024 Githmi Sports Goods.
                </p>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Global styles for custom scrollbar */}
      <style
        dangerouslySetInnerHTML={{
          __html: `
        :root {
          --scrollbar-thumb: #cbd5e1;
          --scrollbar-track: #f1f5f9;
        }
        .dark {
          --scrollbar-thumb: #475569;
          --scrollbar-track: #1e293b;
        }
        ::-webkit-scrollbar {
          width: 8px;
        }
        ::-webkit-scrollbar-track {
          background: var(--scrollbar-track);
        }
        ::-webkit-scrollbar-thumb {
          background: var(--scrollbar-thumb);
          border-radius: 4px;
        }
        ::-webkit-scrollbar-thumb:hover {
          background: #94a3b8;
        }
        .dark ::-webkit-scrollbar-thumb:hover {
          background: #64748b;
        }
      `,
        }}
      />
    </>
  );
}

import { createContext, useContext, useEffect, useState } from "react";
import { auth } from "../lib/firebase";
import { onAuthStateChanged, signOut } from "firebase/auth";
import axios from "axios";

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  const loadUserFromBackend = async (firebaseUser) => {
    try {
      const idToken = await firebaseUser.getIdToken();
      localStorage.setItem("token", idToken);

      const response = await axios.get(`${import.meta.env.VITE_BACKEND_URL}/api/user/current`, {
        headers: { Authorization: `Bearer ${idToken}` },
      });

      setUser(response.data.user);
    } catch (error) {
      console.error("Failed to load user from backend:", error);
      setUser(null);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (firebaseUser) => {
      if (firebaseUser) {
        loadUserFromBackend(firebaseUser);
      } else {
        localStorage.removeItem("token");
        setUser(null);
        setLoading(false);
      }
    });

    return () => unsubscribe();
  }, []);

  const logout = async () => {
    try {
      await signOut(auth);
      localStorage.removeItem("token");
      setUser(null);
    } catch (error) {
      console.error("Logout failed:", error);
    }
  };

  return (
    <AuthContext.Provider value={{ user, loading, logout, setUser }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);

import { useState, useEffect } from "react";
import axios from "axios";
import toast from "react-hot-toast";
import { FiCheckCircle, FiTrash2, FiMail, FiSend, FiX } from "react-icons/fi";

const AdminMessages = () => {
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);

  // Reply Modal State
  const [replyModalOpen, setReplyModalOpen] = useState(false);
  const [activeReplyMsg, setActiveReplyMsg] = useState(null);
  const [replyText, setReplyText] = useState("");
  const [sendingReply, setSendingReply] = useState(false);

  const fetchMessages = async () => {
    try {
      const baseUrl = import.meta.env.VITE_BACKEND_URL;
      const token = localStorage.getItem("token");
      const config = { headers: { Authorization: `Bearer ${token}` } };

      const response = await axios.get(`${baseUrl}/api/messages`, config);
      const data = response.data.messages || [];
      setMessages(Array.isArray(data) ? data : []);
    } catch (error) {
      toast.error("Failed to load messages");
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchMessages();

    // Automatically poll every 10 seconds for live inbox updates
    const interval = setInterval(fetchMessages, 10000);
    return () => clearInterval(interval);
  }, []);

  const handleToggleStatus = async (msgId, currentStatus) => {
    try {
      const newStatus = currentStatus === "Unread" ? "Read" : "Unread";
      const baseUrl = import.meta.env.VITE_BACKEND_URL;
      const token = localStorage.getItem("token");
      const config = { headers: { Authorization: `Bearer ${token}` } };

      await axios.put(
        `${baseUrl}/api/messages/${msgId}/status`,
        { status: newStatus },
        config
      );

      toast.success(`Message marked as ${newStatus}`);
      fetchMessages();
    } catch (error) {
      toast.error("Failed to update status");
    }
  };

  const handleDelete = async (msgId) => {
    if (!window.confirm("Are you sure you want to permanently delete this message?")) return;

    try {
      const baseUrl = import.meta.env.VITE_BACKEND_URL;
      const token = localStorage.getItem("token");
      const config = { headers: { Authorization: `Bearer ${token}` } };

      await axios.delete(`${baseUrl}/api/messages/${msgId}`, config);
      toast.success("Message deleted successfully");
      fetchMessages();
    } catch (error) {
      toast.error("Failed to delete message");
    }
  };

  const openReplyModal = (msg) => {
    setActiveReplyMsg(msg);
    setReplyText("");
    setReplyModalOpen(true);
  };

  const handleSendReply = async () => {
    if (!replyText.trim()) {
      return toast.error("Please enter a reply message.");
    }

    setSendingReply(true);
    try {
      const baseUrl = import.meta.env.VITE_BACKEND_URL;
      const token = localStorage.getItem("token");
      const config = { headers: { Authorization: `Bearer ${token}` } };

      await axios.post(
        `${baseUrl}/api/messages/${activeReplyMsg._id}/reply`,
        { replyMessage: replyText },
        config
      );

      toast.success("Reply sent successfully via email!");
      setReplyModalOpen(false);
      setActiveReplyMsg(null);
      fetchMessages(); // Refresh to show it as read
    } catch (error) {
      toast.error(error.response?.data?.message || "Failed to send email reply.");
    } finally {
      setSendingReply(false);
    }
  };

  return (
    <div className="space-y-6 relative">
      <div className="flex justify-between items-center bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
        <h2 className="text-xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
          <FiMail className="text-indigo-600" /> Inbox Messages
        </h2>
        <div className="text-sm text-gray-500 dark:text-gray-400 font-medium bg-gray-100 dark:bg-gray-700 px-4 py-2 rounded-xl">
          Unread Messages: {messages.filter(m => m.status === 'Unread').length}
        </div>
      </div>

      <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-gray-50 dark:bg-gray-700/50 border-b border-gray-200 dark:border-gray-700 text-gray-500 dark:text-gray-400 text-sm">
                <th className="p-4 font-medium">Customer Details</th>
                <th className="p-4 font-medium">Subject</th>
                <th className="p-4 font-medium max-w-sm">Message Content</th>
                <th className="p-4 font-medium">Status</th>
                <th className="p-4 font-medium text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
              {loading ? (
                <tr>
                  <td colSpan="5" className="p-4 text-center text-gray-500">Loading inbox...</td>
                </tr>
              ) : messages.length === 0 ? (
                <tr>
                  <td colSpan="5" className="p-4 text-center text-gray-500">Inbox is empty. No messages found.</td>
                </tr>
              ) : (
                messages.map((msg) => (
                  <tr key={msg._id} className={`transition-colors ${msg.status === 'Unread' ? 'bg-indigo-50/50 dark:bg-indigo-900/10 font-medium' : 'hover:bg-gray-50 dark:hover:bg-gray-700/20'}`}>
                    <td className="p-4">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-gray-900 dark:text-gray-200">{msg.name}</p>
                        {msg.status === "Unread" && (
                          <span 
                            className="w-2 h-2 rounded-full bg-red-500 shadow-[0_0_8px_rgba(239, 68, 68, 0.5)] animate-pulse" 
                            title="New Message"
                          ></span>
                        )}
                      </div>
                      <p className="text-xs text-gray-500 dark:text-gray-400">{msg.email}</p>
                      {msg.phone && <p className="text-xs text-gray-400 dark:text-gray-500 mt-1">{msg.phone}</p>}
                    </td>
                    <td className="p-4 text-sm font-semibold text-gray-800 dark:text-gray-300">
                      {msg.subject}
                    </td>
                    <td className="p-4 max-w-sm">
                      <p className="text-sm text-gray-700 dark:text-gray-400 whitespace-pre-wrap">{msg.message}</p>
                      <p className="text-xs text-gray-400 mt-2">{new Date(msg.createdAt).toLocaleString()}</p>
                    </td>
                    <td className="p-4 text-sm">
                      <span className={`px-2 py-1 rounded-full text-xs font-bold ${msg.status === 'Unread' ? 'bg-indigo-100 text-indigo-700 dark:bg-indigo-900/30 dark:text-indigo-400' : 'bg-gray-100 text-gray-600 dark:bg-gray-700 dark:text-gray-400'}`}>
                        {msg.status}
                      </span>
                    </td>
                    <td className="p-4 text-right space-x-2 whitespace-nowrap">
                      <button
                        onClick={() => openReplyModal(msg)}
                        className="p-2 text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg transition-colors"
                        title="Reply via Email"
                      >
                        <FiSend className="w-5 h-5" />
                      </button>
                      <button
                        onClick={() => handleToggleStatus(msg._id, msg.status)}
                        className={`p-2 rounded-lg transition-colors ${msg.status === 'Unread' ? "text-green-600 hover:bg-green-50 dark:hover:bg-green-900/20" : "text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700"}`}
                        title={msg.status === 'Unread' ? "Mark as Read" : "Mark as Unread"}
                      >
                        {msg.status === 'Unread' ? <FiCheckCircle className="w-5 h-5"/> : <FiMail className="w-5 h-5" />}
                      </button>
                      <button
                        onClick={() => handleDelete(msg._id)}
                        className="p-2 text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
                        title="Delete Message"
                      >
                        <FiTrash2 className="w-5 h-5" />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Reply Modal overlay */}
      {replyModalOpen && activeReplyMsg && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-xl w-full max-w-2xl overflow-hidden border border-gray-200 dark:border-gray-700">
            <div className="flex justify-between items-center p-6 border-b border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800">
              <h3 className="text-xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                <FiSend className="text-indigo-600" /> Reply to {activeReplyMsg.name}
              </h3>
              <button
                onClick={() => setReplyModalOpen(false)}
                className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 transition-colors"
              >
                <FiX className="w-6 h-6" />
              </button>
            </div>
            <div className="p-6">
              <div className="mb-4 bg-gray-50 dark:bg-gray-900 p-4 rounded-xl border border-gray-100 dark:border-gray-700">
                <p className="text-xs text-gray-500 tracking-wide uppercase font-semibold mb-1">To: {activeReplyMsg.email}</p>
                <p className="text-sm font-semibold text-gray-800 dark:text-gray-200">Re: {activeReplyMsg.subject}</p>
                <div className="mt-2 text-sm text-gray-600 dark:text-gray-400 pl-3 border-l-2 border-indigo-300 dark:border-indigo-800 italic">
                  {activeReplyMsg.message}
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                  Your Response
                </label>
                <textarea
                  className="w-full rounded-xl border border-gray-300 dark:border-gray-600 p-4 text-sm bg-white dark:bg-gray-700 text-gray-800 dark:text-gray-100 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all resize-y min-h-[150px]"
                  placeholder="Type your reply here..."
                  value={replyText}
                  onChange={(e) => setReplyText(e.target.value)}
                  disabled={sendingReply}
                ></textarea>
              </div>

              <div className="mt-6 flex justify-end gap-3">
                <button
                  className="px-5 py-2.5 rounded-xl border border-gray-300 text-gray-700 dark:text-gray-300 dark:border-gray-600 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors font-medium text-sm"
                  onClick={() => setReplyModalOpen(false)}
                  disabled={sendingReply}
                >
                  Cancel
                </button>
                <button
                  className="px-6 py-2.5 rounded-xl bg-indigo-600 hover:bg-indigo-700 text-white font-medium text-sm shadow-md hover:shadow-lg transition-all flex items-center justify-center min-w-[120px]"
                  onClick={handleSendReply}
                  disabled={sendingReply}
                >
                  {sendingReply ? (
                    <span className="animate-pulse">Sending...</span>
                  ) : (
                     <div className="flex items-center">Send Reply <FiSend className="ml-2 w-4 h-4"/></div>
                  )}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminMessages;

import { useState, useEffect } from "react";
import axios from "axios";
import toast from "react-hot-toast";
import { FiEdit2, FiTrash2, FiPlus, FiX } from "react-icons/fi";
import ImageUploader from "../../components/admin/ImageUploader";

const AdminProducts = () => {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState(null);

  const [formData, setFormData] = useState({
    productId: "",
    name: "",
    price: "",
    labeledPrice: "",
    stock: "",
    category: "General",
    description: "",
    images: "",
    isBestDeal: false,
    isLatest: false,
    isReadyToShip: false,
  });

  const fetchProducts = async () => {
    try {
      const baseUrl = import.meta.env.VITE_BACKEND_URL;
      const response = await axios.get(`${baseUrl}/api/product`);
      // Adapt based on actual API response
      const data = Array.isArray(response.data) ? response.data : response.data.products || [];
      setProducts(data);
    } catch (error) {
      toast.error("Failed to load products");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchProducts();
  }, []);

  const openModal = (product = null) => {
    if (product) {
      setEditingProduct(product);
      setFormData({
        productId: product.productId || "",
        name: product.name || "",
        price: product.price || "",
        labeledPrice: product.labeledPrice || "",
        stock: product.stock || "",
        category: product.category || "General",
        description: product.description || "",
        images: product.images || [],
        isBestDeal: product.isBestDeal || false,
        isLatest: product.isLatest || false,
        isReadyToShip: product.isReadyToShip || false,
      });
    } else {
      setEditingProduct(null);
      setFormData({
        productId: "",
        name: "",
        price: "",
        labeledPrice: "",
        stock: "",
        category: "General",
        description: "",
        images: [],
        isBestDeal: false,
        isLatest: false,
        isReadyToShip: false,
      });
    }
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingProduct(null);
  };

  const handleInputChange = (e) => {
    const { name, value, type, checked } = e.target;
    const inputValue = type === "checkbox" ? checked : value;

    setFormData((prev) => ({ ...prev, [name]: inputValue }));

    if (name === "name") {
      if (value.trim().length > 2) {
        const suggested = suggestCategory(value);
        setFormData((prev) => ({ ...prev, category: suggested }));
      } else {
        setFormData((prev) => ({ ...prev, category: "General" }));
      }
    }
  };

  const suggestCategory = (productName) => {
    const categories = {
      "Footwear": ["shoe", "sneaker", "boot", "cleat", "running", "zoom", "pegasus", "spikes"],
      "Football": ["football", "soccer", "shin guard", "messi", "ronaldo", "fifa"],
      "Cricket": ["cricket", "bat", "pad", "helmet", "stump", "sg", "mrf", "kookaburra", "ball"],
      "Basketball": ["basketball", "hoop", "jordan", "lebron", "lakers", "nba"],
      "Racket Sports": ["tennis", "badminton", "racket", "shuttlecock", "squash", "yonex", "wilson"],
      "Gym & Fitness": ["dumbbell", "weight", "gym", "yoga", "mat", "fitness", "treadmill", "plate"],
      "Swimming": ["swim", "goggle", "cap", "speedo", "pool", "fins"],
      "Apparel": ["jersey", "short", "shirt", "socks", "tracksuit", "jacket", "glove", "cap", "hat", "t-shirt"],
      "Indoor Games": ["carrom", "board", "chess", "dart", "billiard", "snooker", "table tennis", "ping pong"]
    };

    for (const [category, keywords] of Object.entries(categories)) {
      if (keywords.some(keyword => new RegExp(`\\b${keyword}\\b`, "i").test(productName))) {
        return category;
      }
    }
    return "General";
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const token = localStorage.getItem("token");
    const config = { headers: { Authorization: `Bearer ${token}` } };
    const baseUrl = import.meta.env.VITE_BACKEND_URL;

    const payload = {
      ...formData,
      price: Number(formData.price),
      labeledPrice: Number(formData.labeledPrice),
      stock: Number(formData.stock),
      images: formData.images,
    };

    try {
      if (editingProduct) {
        await axios.put(`${baseUrl}/api/product/${editingProduct.productId}`, payload, config);
        toast.success("Product updated successfully");
      } else {
        await axios.post(`${baseUrl}/api/product`, payload, config);
        toast.success("Product created successfully");
      }
      closeModal();
      fetchProducts();
    } catch (error) {
      toast.error(error.response?.data?.message || "Operation failed");
    }
  };

  const handleDelete = async (productId) => {
    if (!window.confirm("Are you sure you want to delete this product?")) return;

    try {
      const token = localStorage.getItem("token");
      const config = { headers: { Authorization: `Bearer ${token}` } };
      const baseUrl = import.meta.env.VITE_BACKEND_URL;

      await axios.delete(`${baseUrl}/api/product/${productId}`, config);
      toast.success("Product deleted");
      fetchProducts();
    } catch (error) {
      toast.error("Failed to delete product");
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
        <h2 className="text-xl font-bold text-gray-800 dark:text-white">Products Management</h2>
        <button
          onClick={() => openModal()}
          className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-xl transition-colors text-sm font-medium"
        >
          <FiPlus /> Add Product
        </button>
      </div>

      <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-gray-50 dark:bg-gray-700/50 border-b border-gray-200 dark:border-gray-700 text-gray-500 dark:text-gray-400 text-sm">
                <th className="p-4 font-medium">Image</th>
                <th className="p-4 font-medium">Product ID</th>
                <th className="p-4 font-medium">Name</th>
                <th className="p-4 font-medium">Price</th>
                <th className="p-4 font-medium">Stock</th>
                <th className="p-4 font-medium text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
              {loading ? (
                <tr>
                  <td colSpan="6" className="p-4 text-center text-gray-500">Loading...</td>
                </tr>
              ) : products.length === 0 ? (
                <tr>
                  <td colSpan="6" className="p-4 text-center text-gray-500">No products found.</td>
                </tr>
              ) : (
                products.map((product) => (
                  <tr key={product._id || product.productId} className="hover:bg-gray-50 dark:hover:bg-gray-700/20 transition-colors">
                    <td className="p-4">
                      {product.images && product.images.length > 0 ? (
                        <img src={product.images[0]} alt={product.name} className="w-12 h-12 object-cover rounded-lg" />
                      ) : (
                        <div className="w-12 h-12 bg-gray-200 dark:bg-gray-700 rounded-lg flex items-center justify-center text-xs text-gray-500">No IMG</div>
                      )}
                    </td>
                    <td className="p-4 text-sm font-medium text-gray-900 dark:text-gray-200">{product.productId}</td>
                    <td className="p-4 text-sm text-gray-700 dark:text-gray-300">{product.name}</td>
                    <td className="p-4 text-sm text-gray-700 dark:text-gray-300">${product.price}</td>
                    <td className="p-4 text-sm text-gray-700 dark:text-gray-300">
                      <span className={`px-2 py-1 rounded-full text-xs font-medium ${product.stock > 0 ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'}`}>
                        {product.stock}
                      </span>
                    </td>
                    <td className="p-4 text-right space-x-2">
                      <button
                        onClick={() => openModal(product)}
                        className="p-2 text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg transition-colors"
                      >
                        <FiEdit2 />
                      </button>
                      <button
                        onClick={() => handleDelete(product.productId)}
                        className="p-2 text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
                      >
                        <FiTrash2 />
                      </button>
                    </td>
                  </tr>

                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex justify-center items-center p-4">
          <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-xl w-full max-w-2xl max-h-[90vh] overflow-y-auto w-full">
            <div className="flex justify-between items-center p-6 border-b border-gray-200 dark:border-gray-700 sticky top-0 bg-white dark:bg-gray-800">
              <h3 className="text-xl font-bold text-gray-900 dark:text-white">
                {editingProduct ? "Edit Product" : "Add New Product"}
              </h3>
              <button onClick={closeModal} className="text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200">
                <FiX className="w-6 h-6" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Product ID</label>
                  <input
                    type="text"
                    name="productId"
                    value={formData.productId}
                    onChange={handleInputChange}
                    required
                    className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-xl bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Name</label>
                  <input
                    type="text"
                    name="name"
                    value={formData.name}
                    onChange={handleInputChange}
                    required
                    className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-xl bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Selling Price</label>
                  <input
                    type="number"
                    name="price"
                    value={formData.price}
                    onChange={handleInputChange}
                    required
                    min="0"
                    className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-xl bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Labeled Price</label>
                  <input
                    type="number"
                    name="labeledPrice"
                    value={formData.labeledPrice}
                    onChange={handleInputChange}
                    required
                    min="0"
                    className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-xl bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Stock</label>
                  <input
                    type="number"
                    name="stock"
                    value={formData.stock}
                    onChange={handleInputChange}
                    required
                    min="0"
                    className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-xl bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
                <div>
                  <div className="flex justify-between items-center mb-1">
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Category</label>
                    <span className="text-[10px] text-indigo-500 font-bold bg-indigo-50 dark:bg-indigo-900/30 px-2 py-0.5 rounded-full">✨ AI Enabled</span>
                  </div>
                  <input
                    type="text"
                    name="category"
                    value={formData.category}
                    onChange={handleInputChange}
                    className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-xl bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Product Images</label>
                <ImageUploader
                  images={formData.images}
                  onChange={(urls) => setFormData((prev) => ({ ...prev, images: urls }))}
                />
              </div>

              <div className="bg-gray-50 dark:bg-gray-700/50 p-4 rounded-xl border border-gray-200 dark:border-gray-600">
                <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 border-b border-gray-200 dark:border-gray-600 pb-2 mb-3">
                  Homepage Display Sections
                </label>
                <div className="flex flex-wrap gap-6">
                  <label className="flex items-center space-x-2 text-sm text-gray-700 dark:text-gray-300 cursor-pointer">
                    <input
                      type="checkbox"
                      name="isBestDeal"
                      checked={formData.isBestDeal}
                      onChange={handleInputChange}
                      className="w-4 h-4 rounded border-gray-300 text-indigo-600 focus:ring-indigo-500"
                    />
                    <span className="font-medium">Best Deals</span>
                  </label>
                  <label className="flex items-center space-x-2 text-sm text-gray-700 dark:text-gray-300 cursor-pointer">
                    <input
                      type="checkbox"
                      name="isLatest"
                      checked={formData.isLatest}
                      onChange={handleInputChange}
                      className="w-4 h-4 rounded border-gray-300 text-indigo-600 focus:ring-indigo-500"
                    />
                    <span className="font-medium">New Arrivals</span>
                  </label>
                  <label className="flex items-center space-x-2 text-sm text-gray-700 dark:text-gray-300 cursor-pointer">
                    <input
                      type="checkbox"
                      name="isReadyToShip"
                      checked={formData.isReadyToShip}
                      onChange={handleInputChange}
                      className="w-4 h-4 rounded border-gray-300 text-indigo-600 focus:ring-indigo-500"
                    />
                    <span className="font-medium">Limited Stock</span>
                  </label>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Description</label>
                <textarea
                  name="description"
                  value={formData.description}
                  onChange={handleInputChange}
                  rows="3"
                  className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-xl bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none"
                ></textarea>
              </div>

              <div className="flex justify-end gap-3 mt-6">
                <button
                  type="button"
                  onClick={closeModal}
                  className="px-6 py-2 rounded-xl text-gray-700 bg-gray-100 hover:bg-gray-200 dark:text-gray-300 dark:bg-gray-700 dark:hover:bg-gray-600 transition-colors"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="px-6 py-2 rounded-xl text-white bg-indigo-600 hover:bg-indigo-700 transition-colors"
                >
                  {editingProduct ? "Save Changes" : "Create Product"}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminProducts;

import { useState, useEffect } from "react";
import axios from "axios";
import toast from "react-hot-toast";
import { FiCheckCircle, FiXCircle, FiTrash2 } from "react-icons/fi";
import { FaStar } from "react-icons/fa";

const AdminReviews = () => {
  const [reviews, setReviews] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchReviews = async () => {
    try {
      const baseUrl = import.meta.env.VITE_BACKEND_URL;
      const token = localStorage.getItem("token");
      const config = { headers: { Authorization: `Bearer ${token}` } };

      const response = await axios.get(`${baseUrl}/api/reviews`, config);
      const data = response.data.reviews || response.data || [];
      setReviews(Array.isArray(data) ? data : []);
    } catch (error) {
      toast.error("Failed to load reviews");
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchReviews();
  }, []);

  const handleToggleApproval = async (reviewId, currentStatus) => {
    try {
      const baseUrl = import.meta.env.VITE_BACKEND_URL;
      const token = localStorage.getItem("token");
      const config = { headers: { Authorization: `Bearer ${token}` } };

      await axios.put(
        `${baseUrl}/api/reviews/${reviewId}/approve`,
        { isApproved: !currentStatus },
        config
      );

      toast.success(`Review ${!currentStatus ? "approved" : "hidden"} successfully`);
      fetchReviews();
    } catch (error) {
      toast.error("Failed to update review status");
    }
  };

  const handleDelete = async (reviewId) => {
    if (!window.confirm("Are you sure you want to permanently delete this review?")) return;

    try {
      const baseUrl = import.meta.env.VITE_BACKEND_URL;
      const token = localStorage.getItem("token");
      const config = { headers: { Authorization: `Bearer ${token}` } };

      await axios.delete(`${baseUrl}/api/reviews/${reviewId}`, config);
      toast.success("Review deleted successfully");
      fetchReviews();
    } catch (error) {
      toast.error("Failed to delete review");
    }
  };

  const renderStars = (rating) => {
    return (
      <div className="flex items-center space-x-1">
        {[...Array(5)].map((_, index) => (
          <FaStar
            key={index}
            className={`text-xs ${index < rating ? "text-yellow-400" : "text-gray-300 dark:text-gray-600"}`}
          />
        ))}
      </div>
    );
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
        <h2 className="text-xl font-bold text-gray-800 dark:text-white">Customer Reviews</h2>
        <div className="text-sm text-gray-500 dark:text-gray-400 font-medium bg-gray-100 dark:bg-gray-700 px-4 py-2 rounded-xl">
          Total Reviews: {reviews.length}
        </div>
      </div>

      <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-gray-50 dark:bg-gray-700/50 border-b border-gray-200 dark:border-gray-700 text-gray-500 dark:text-gray-400 text-sm">
                <th className="p-4 font-medium">Customer</th>
                <th className="p-4 font-medium">Product</th>
                <th className="p-4 font-medium">Rating</th>
                <th className="p-4 font-medium">Review Content</th>
                <th className="p-4 font-medium">Status</th>
                <th className="p-4 font-medium text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
              {loading ? (
                <tr>
                  <td colSpan="6" className="p-4 text-center text-gray-500">Loading...</td>
                </tr>
              ) : reviews.length === 0 ? (
                <tr>
                  <td colSpan="6" className="p-4 text-center text-gray-500">No reviews found.</td>
                </tr>
              ) : (
                reviews.map((review) => (
                  <tr key={review._id} className="hover:bg-gray-50 dark:hover:bg-gray-700/20 transition-colors">
                    <td className="p-4">
                      <div className="flex items-center gap-3">
                        {review.avatar ? (
                            <img src={review.avatar} alt="avatar" className="w-8 h-8 rounded-full object-cover" />
                        ) : (
                            <div className="w-8 h-8 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-bold text-xs uppercase">{review.name?.charAt(0) || "U"}</div>
                        )}
                        <div>
                          <p className="text-sm font-medium text-gray-900 dark:text-gray-200">{review.name}</p>
                          <p className="text-xs text-gray-500 dark:text-gray-400">{review.email}</p>
                        </div>
                      </div>
                    </td>
                    <td className="p-4 text-sm font-medium text-gray-700 dark:text-gray-300">
                      {review.productId}
                    </td>
                    <td className="p-4">
                      {renderStars(review.rating)}
                    </td>
                    <td className="p-4 max-w-sm">
                      <p className="text-sm font-bold text-gray-900 dark:text-gray-200 mb-1">{review.title}</p>
                      <p className="text-xs text-gray-600 dark:text-gray-400 line-clamp-2">{review.comment}</p>
                    </td>
                    <td className="p-4 text-sm">
                      <span className={`px-2 py-1 rounded-full text-xs font-medium ${review.isApproved ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-400'}`}>
                        {review.isApproved ? "Approved" : "Hidden"}
                      </span>
                    </td>
                    <td className="p-4 text-right space-x-2 whitespace-nowrap">
                      <button
                        onClick={() => handleToggleApproval(review._id, review.isApproved)}
                        className={`p-2 rounded-lg transition-colors ${review.isApproved ? "text-yellow-600 hover:bg-yellow-50 dark:hover:bg-yellow-900/20" : "text-green-600 hover:bg-green-50 dark:hover:bg-green-900/20"}`}
                        title={review.isApproved ? "Hide Review" : "Approve Review"}
                      >
                        {review.isApproved ? <FiXCircle className="w-5 h-5"/> : <FiCheckCircle className="w-5 h-5" />}
                      </button>
                      <button
                        onClick={() => handleDelete(review._id)}
                        className="p-2 text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
                        title="Delete Review"
                      >
                        <FiTrash2 className="w-5 h-5" />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminReviews;

import { useState, useEffect } from "react";
import axios from "axios";
import toast from "react-hot-toast";
import { FiTrash2 } from "react-icons/fi";

const AdminUsers = () => {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchUsers = async () => {
    try {
      const token = localStorage.getItem("token");
      const config = { headers: { Authorization: `Bearer ${token}` } };
      const baseUrl = import.meta.env.VITE_BACKEND_URL;

      const response = await axios.get(`${baseUrl}/api/user`, config);
      const data = response.data.list || response.data || [];
      setUsers(Array.isArray(data) ? data : []);
    } catch (error) {
      toast.error("Failed to load users");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUsers();
  }, []);

  const handleDelete = async (id) => {
