      const token = localStorage.getItem("token");
      const config = { headers: { Authorization: `Bearer ${token}` } };
      const baseUrl = import.meta.env.VITE_BACKEND_URL;

      await axios.delete(`${baseUrl}/api/user/${id}`, config);
